final:
module Counter_4_updown(
   input                clk,
   input                rst,
   input                en,
   input                up,
   output reg [3:0]     obf_Q
);
    always@(posedge clk)begin
        if(rst) obf_Q <= 4'd0;
        else if(en) begin
            if(up) obf_Q <= obf_Q + 1;
            else obf_Q <= obf_Q - 1;
        end
    end
endmodule
